vec![
    ts!("cfa11-1", "computer", "frontend", "accessibility", "WCAG 2.1/2.2", "Web内容无障碍指南，包含可感知、可操作、可理解和健壮四大原则，A/AA/AAA三级标准。"),
    ts!("cfa11-2", "computer", "frontend", "accessibility", "ARIA / Accessible Rich Internet Applications", "WAI-ARIA规范，通过role、aria-*属性补充HTML语义，增强动态内容和复杂控件的可访问性。"),
    ts!("cfa11-3", "computer", "frontend", "accessibility", "语义化HTML", "使用具有明确结构意义的标签（header/nav/main/footer/article等），让辅助技术更好理解页面结构。"),
    ts!("cfa11-4", "computer", "frontend", "accessibility", "屏幕阅读器 / Screen Reader", "将屏幕内容转换为语音或盲文的辅助软件，常见有JAWS、NVDA、VoiceOver和TalkBack。"),
    ts!("cfa11-5", "computer", "frontend", "accessibility", "键盘导航 / Keyboard Navigation", "所有交互功能可通过键盘完成，Tab键移动焦点，Enter/Space激活，Escape关闭。"),
    ts!("cfa11-6", "computer", "frontend", "accessibility", "焦点管理 / Focus Management", "合理设置焦点顺序，模态框打开时聚焦到内部，关闭时返回触发元素。"),
    ts!("cfa11-7", "computer", "frontend", "accessibility", "焦点陷阱 / Focus Trap", "在模态框和对话框中循环焦点，Tab键不会跳出对话框访问背景内容。"),
    ts!("cfa11-8", "computer", "frontend", "accessibility", "跳过链接 / Skip Link", "页面顶部第一个可聚焦元素，允许键盘用户跳过重复导航直接进入主内容。"),
    ts!("cfa11-9", "computer", "frontend", "accessibility", "颜色对比度 / Color Contrast", "文本与背景最低对比度AA级4.5:1（普通文本）和3:1（大文本），AAA级更高。"),
    ts!("cfa11-10", "computer", "frontend", "accessibility", "非颜色区分", "不用颜色作为传达信息的唯一方式，图表和表单错误状态应同时使用图标或文字标识。"),
    ts!("cfa11-11", "computer", "frontend", "accessibility", "替代文本 / Alt Text", "img标签的alt属性提供图片的文字描述，让屏幕阅读器用户理解图片内容和功能。"),
    ts!("cfa11-12", "computer", "frontend", "accessibility", "表单标签 / Form Labels", "每个表单控件都有关联的label标签，使用for-id或包裹方式关联，确保辅助技术正确播报。"),
    ts!("cfa11-13", "computer", "frontend", "accessibility", "错误提示 / Error Messaging", "表单验证错误使用ARIA与控件关联，错误信息清晰且提供修复指导。"),
    ts!("cfa11-14", "computer", "frontend", "accessibility", "ARIA Live Regions", "动态内容更新的区域通过aria-live属性自动通知屏幕阅读器，无需用户操作。"),
    ts!("cfa11-15", "computer", "frontend", "accessibility", "标题层级 / Heading Hierarchy", "页面只有一个h1，标题层级h1-h6不跳级使用，形成清晰的文档大纲。"),
    ts!("cfa11-16", "computer", "frontend", "accessibility", "Landmarks / 地标角色", "使用HTML5语义标签或ARIA landmarks标记页面的主要区域，方便快速导航。"),
    ts!("cfa11-17", "computer", "frontend", "accessibility", "可调整文本 / Resizable Text", "文本可放大到200%不影响布局和功能，使用相对单位（rem/em）而非绝对单位（px）定义字号。"),
    ts!("cfa11-18", "computer", "frontend", "accessibility", "触摸目标 / Touch Target", "可点击元素的尺寸至少44x44 CSS像素，确保手指精确操作。"),
    ts!("cfa11-19", "computer", "frontend", "accessibility", "运动偏好 / prefers-reduced-motion", "检测用户系统的减少运动设置，关闭或减弱动画效果，防止前庭系统敏感用户不适。"),
    ts!("cfa11-20", "computer", "frontend", "accessibility", "色彩偏好 / prefers-color-scheme", "检测用户系统明暗模式偏好，自动切换界面主题。"),
    ts!("cfa11-21", "computer", "frontend", "accessibility", "对比度偏好 / prefers-contrast", "检测用户系统高对比度偏好，提供更适合弱视用户的界面变体。"),
    ts!("cfa11-22", "computer", "frontend", "accessibility", "Aria-label / Aria-labelledby", "为没有可见标签的元素提供可访问名称，aria-labelledby引用其他元素的文本。"),
    ts!("cfa11-23", "computer", "frontend", "accessibility", "Aria-describedby", "关联描述性文本到表单控件，提供额外的帮助信息，屏幕阅读器会在标签之后播报。"),
    ts!("cfa11-24", "computer", "frontend", "accessibility", "Aria-hidden", "从辅助技术中隐藏装饰性或重复性元素，避免对用户造成信息噪音。"),
    ts!("cfa11-25", "computer", "frontend", "accessibility", "Tabindex / 焦点管理", "控制元素的键盘可聚焦性，0加入自然顺序，-1可脚本聚焦，>0不推荐。"),
    ts!("cfa11-26", "computer", "frontend", "accessibility", "无障碍名称 / Accessible Name", "辅助技术识别元素的名称，计算顺序：aria-labelledby>aria-label>原生标签>title属性。"),
    ts!("cfa11-27", "computer", "frontend", "accessibility", "无障碍描述 / Accessible Description", "辅助技术识别元素的描述，计算来源包括aria-describedby、title属性和内部文本。"),
    ts!("cfa11-28", "computer", "frontend", "accessibility", "音频描述 / Audio Description", "视频中插入的旁白描述，解释纯视觉信息，帮助视障用户理解视频内容。"),
    ts!("cfa11-29", "computer", "frontend", "accessibility", "字幕 / Captions / Subtitles", "将对话和重要声音转写为屏幕文字，帮助听障用户和多语言用户理解内容。"),
    ts!("cfa11-30", "computer", "frontend", "accessibility", "语音输入 / Voice Input", "通过语音命令操作界面，Dragon NaturallySpeaking等软件支持，确保所有功能可语音触发。"),
    ts!("cfa11-31", "computer", "frontend", "accessibility", "开关控制 / Switch Control", "通过单一开关（呼吸管、头部棒等）进行二进制输入和界面扫描导航。"),
    ts!("cfa11-32", "computer", "frontend", "accessibility", "放大镜 / Screen Magnifier", "将屏幕局部区域放大的辅助软件，常见于操作系统内置辅助功能。"),
    ts!("cfa11-33", "computer", "frontend", "accessibility", "高对比度模式 / High Contrast Mode", "操作系统级别的颜色反转和简化，确保界面在该模式下仍可正常使用。"),
    ts!("cfa11-34", "computer", "frontend", "accessibility", "a11y / Accessibility缩写", "accessibility的数字化缩写，a和y之间有11个字母因此得名。"),
    ts!("cfa11-35", "computer", "frontend", "accessibility", "可访问性测试 / a11y Testing", "使用自动化工具（axe/Lighthouse）和手动测试（键盘导航/屏幕阅读器）验证可访问性。"),
    ts!("cfa11-36", "computer", "frontend", "accessibility", "axe-core / Deque", "最流行的自动化可访问性测试引擎，Jest和Cypress有对应集成插件。"),
    ts!("cfa11-37", "computer", "frontend", "accessibility", "ARIA角色 / Role", "定义元素在辅助技术中的语义角色，如button、navigation、alert等。"),
    ts!("cfa11-38", "computer", "frontend", "accessibility", "ARIA状态和属性", "反映元素当前状态的属性，如aria-expanded、aria-selected、aria-checked。"),
    ts!("cfa11-39", "computer", "frontend", "accessibility", "ARIA最佳实践", "W3C的ARIA Authoring Practices Guide，提供常见UI模式的键盘交互和ARIA使用范例。"),
    ts!("cfa11-40", "computer", "frontend", "accessibility", "包容性设计 / Inclusive Design", "从设计之初就考虑多样化用户需求，涵盖永久、暂时和情境性障碍。"),
    ts!("cfa11-41", "computer", "frontend", "accessibility", "通用设计 / Universal Design", "产品或环境最大程度为所有人使用无需额外调整的设计理念，7项基本原则。"),
    ts!("cfa11-42", "computer", "frontend", "accessibility", "无障碍声明 / Accessibility Statement", "网站公开的无障碍承诺文档，说明合规标准、已知问题和联系方式。"),
    ts!("cfa11-43", "computer", "frontend", "accessibility", "VPAT / 自愿产品无障碍模板", "标准化文档描述产品满足的无障碍标准，用于政府和企业采购评估。"),
    ts!("cfa11-44", "computer", "frontend", "accessibility", "EN 301 549", "欧洲ICT产品和服务无障碍标准，与WCAG 2.1 AA级对齐。"),
    ts!("cfa11-45", "computer", "frontend", "accessibility", "Section 508", "美国康复法案第508节，要求联邦机构的信息技术对残障人士可访问。"),
    ts!("cfa11-46", "computer", "frontend", "accessibility", "ADA / 美国残疾人法案", "1990年通过，标题III要求公共场所（含网站）对残疾人无障碍。"),
    ts!("cfa11-47", "computer", "frontend", "accessibility", "角色图像 / Decorative Images", "纯装饰无信息价值的图片使用空alt或CSS背景，避免屏幕阅读器重复播报冗余内容。"),
    ts!("cfa11-48", "computer", "frontend", "accessibility", "语音合成 / Speech Synthesis", "Web Speech API中的SpeechSynthesis接口，支持文本到语音的转换输出。"),
    ts!("cfa11-49", "computer", "frontend", "accessibility", "语音识别 / Speech Recognition", "Web Speech API中的SpeechRecognition接口，将语音输入转为文本。"),
    ts!("cfa11-50", "computer", "frontend", "accessibility", "语音输入与输出 / Voice I/O", "语音作为人机交互媒介，包括语音命令控制和文本到语音的合成输出技术。"),
]
